import './FABGroup.scss';
import type { HTMLAttributes, MouseEvent } from 'react';
import React, { Children, cloneElement, isValidElement, ReactElement, useState } from 'react';
import { TestComponentProps } from 'src/types/test-component';
import { classNames } from '../../helpers/classnames';
import { FAB } from './FAB';
import { FABProps } from './FAB.types';

type Falsy = undefined | null | boolean;

export interface FABGroupProps extends TestComponentProps, HTMLAttributes<HTMLDivElement> {
	children: Array<ReactElement<FABProps> | Falsy> | ReactElement<FABProps | Falsy>;
	style?: React.CSSProperties;
	className?: string;
}

export const FABGroup: React.FC<FABGroupProps> = ({ children, style, className, dataTestId = 'FABGroup', ...rest }) => {
	const rawChildren = Children.toArray(children);

	// Эта проверка позволяет избежать клонирования неподходящих элементов
	function isFABElement(child: unknown): child is ReactElement<FABProps> {
		return isValidElement(child) && child.type === FAB;
	}

	// отфильтровываем всех детей, кто не является <FAB />
	const fabChildren = rawChildren.filter(isFABElement);

	if (fabChildren.length === 0) return <></>;

	const mainButtonElement = fabChildren[0];
	const nestedButtons = fabChildren.slice(1);

	const [isOpen, setOpen] = useState(false);
	const handleToggle = () => setOpen(!isOpen);
	// Клонируем главную кнопку, выставляя type="standard" и переопределяя onClick
	const mainButtonCloned = cloneElement<FABProps>(mainButtonElement, {
		type: 'standard',
		onClick: (event: MouseEvent<HTMLElement>) => {
			mainButtonElement.props.onClick?.(event);
			handleToggle?.();
		},
	});

	const nestedCloned = nestedButtons.map(child =>
		cloneElement<FABProps>(child, {
			type: 'mini',
		}),
	);

	return (
		<nav data-testid={dataTestId} className={classNames('fab-group', className)} style={style} role="toolbar" {...rest}>
			{mainButtonCloned}

			<div
				className={classNames('fab-group-nested', {
					'fab-group-nested--open': isOpen,
				})}
			>
				{nestedCloned}
			</div>
		</nav>
	);
};
